"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[231],{5265:e=>{e.exports=JSON.parse('{"functions":[{"name":"Define","desc":"Define (or redefine) a named theme from a partial palette. Returns the *resolved* complete\\npalette, so you can pass it straight to [Theme.Set] or inspect it. Redefining the active\\ntheme recolours live.","params":[{"name":"name","desc":"","lua_type":"string"},{"name":"palette","desc":"","lua_type":"Palette"}],"returns":[{"desc":"","lua_type":"Palette"}],"function_type":"static","source":{"line":290,"path":"src/Theme/init.luau"}},{"name":"Set","desc":"Set the active theme by name or by an explicit (partial) palette. Switching fires\\n[Theme.OnChanged], so every subscribed surface recolours at once. Errors if a name isn\'t\\ndefined.","params":[{"name":"theme","desc":"","lua_type":"string | Palette"}],"returns":[],"function_type":"static","source":{"line":311,"path":"src/Theme/init.luau"}},{"name":"Get","desc":"Read the active palette, or a single group\'s colour. `Theme.Get()` returns the full (always\\ncomplete) palette; `Theme.Get(\\"Error\\")` returns that group\'s `Color3`.","params":[{"name":"group","desc":"","lua_type":"Group?"}],"returns":[{"desc":"","lua_type":"Palette | Color3"}],"function_type":"static","source":{"line":334,"path":"src/Theme/init.luau"}},{"name":"Name","desc":"The name of the active theme, or nil if a raw palette was [Theme.Set] directly.","params":[],"returns":[{"desc":"","lua_type":"string?"}],"function_type":"static","source":{"line":351,"path":"src/Theme/init.luau"}},{"name":"List","desc":"Names of all defined themes.","params":[],"returns":[{"desc":"","lua_type":"{string}"}],"function_type":"static","source":{"line":361,"path":"src/Theme/init.luau"}},{"name":"Groups","desc":"The canonical list of group names (a copy, so callers can\'t mutate the source).","params":[],"returns":[{"desc":"","lua_type":"{Group}"}],"function_type":"static","source":{"line":376,"path":"src/Theme/init.luau"}},{"name":"OnChanged","desc":"Subscribe to theme changes. The callback fires immediately with the current theme and again\\non every [Theme.Set] or redefine. Returns an unsubscribe function. This is how every Karet\\nsurface recolours live.","params":[{"name":"fn","desc":"","lua_type":"(palette: Palette, name: string?) -> ()"}],"returns":[{"desc":"","lua_type":"() -> ()"}],"function_type":"static","source":{"line":389,"path":"src/Theme/init.luau"}}],"properties":[],"types":[{"name":"Group","desc":"One semantic highlight group. The full set covers surfaces (`Background`, `Surface`,\\n`Foreground`, `Muted`, `Border`, `Selection`), accents (`Accent`, `AccentAlt`), syntax\\n(`Command`, `Keyword`, `String`, `Number`, `Comment`, `Operator`, `Variable`, `Type`, ...),\\ndiagnostics (`Error`, `Warn`, `Info`, `Hint`, `Success`) and terminal roles (`Prompt`,\\n`Output`, ...). See [Theme.Groups] for the canonical list.","lua_type":"string","source":{"line":45,"path":"src/Theme/init.luau"}},{"name":"Palette","desc":"A map from [Group] to colour. May be partial when defining a theme (missing groups are\\nderived); [Theme.Get] always returns a complete one.","lua_type":"{ [Group]: Color3 }","source":{"line":94,"path":"src/Theme/init.luau"}}],"name":"Theme","desc":"One semantic colorscheme, piped through every Karet surface (terminal, Kaveat editor,\\nautocomplete, pickers, windows). A theme is not a set of raw frame colours, it\'s a set of\\nsemantic highlight **groups** ([Group]) the way a Neovim colorscheme is, so\\n`Theme.Set(\\"gruvbox\\")` recolours the whole UI at once.\\n\\nAuthors may define a *partial* palette: any group left out is derived from the ones present\\n(Surface lightens Background, Prompt follows Accent, ...), so a minimal theme still produces\\na complete, coherent [Palette]. Reach it as `Karet.Theme`.\\n\\n```lua\\nKaret.Theme.Define(\\"midnight\\", { Background = Color3.fromHex(\\"0b0e14\\"), Accent = Color3.fromHex(\\"7aa2f7\\") })\\nKaret.Theme.Set(\\"midnight\\")\\n```","source":{"line":34,"path":"src/Theme/init.luau"}}')}}]);